   996→function upgradePanelLink(link: any): DataLink {
   997→  let url = link.url;
   998→
   999→  if (!url && link.dashboard) {
  1000→    url = `dashboard/db/${kbn.slugifyForUrl(link.dashboard)}`;
  1001→  }
  1002→
  1003→  if (!url && link.dashUri) {
  1004→    url = `dashboard/${link.dashUri}`;
  1005→  }
  1006→
  1007→  // some models are incomplete and have no dashboard or dashUri
  1008→  if (!url) {
  1009→    url = '/';
  1010→  }
  1011→
  1012→  if (link.keepTime) {
  1013→    url = urlUtil.appendQueryToUrl(url, `$${DataLinkBuiltInVars.keepTime}`);
  1014→  }
  1015→
  1016→  if (link.includeVars) {
  1017→    url = urlUtil.appendQueryToUrl(url, `$${DataLinkBuiltInVars.includeVars}`);
  1018→  }
  1019→
  1020→  if (link.params) {
  1021→    url = urlUtil.appendQueryToUrl(url, link.params);
  1022→  }
  1023→
  1024→  return {
  1025→    url: url,
  1026→    title: link.title,
  1027→    targetBlank: link.targetBlank,
  1028→  };
  1029→}
