    41→	if !ok {
    42→		return false
    43→	}
    44→
    45→	hasUID := false
    46→	if uid, exists := dsRef["uid"]; exists {
    47→		if uidStr, ok := uid.(string); ok && uidStr != "" {
    48→			hasUID = true
    49→		}
    50→	}
    51→
    52→	hasType := false
    53→	if typ, exists := dsRef["type"]; exists {
    54→		if typStr, ok := typ.(string); ok && typStr != "" {
    55→			hasType = true
    56→		}
    57→	}
    58→
    59→	return hasUID || hasType
